final:
module RefModule(  
    input [4:0] data_in,  
    input enable,  
    output reg [4:0] data_out  
);  
  wire [4:0] _tap_data_in = data_in & {5{1'b1}};

    always @(*) begin  
        if (enable)  
            data_out = data_in;  
        else  
            data_out = 5'b00000;  
    end  
endmodule
